<template>
	<view class="">
		<u-navbar :title="navbarTitle" :z-index="980" :custom-back="$util.back">
			<template #right>
				<view class="navbar-right">
					<view class="btn-item check-btn" @click="handelSaveClick">
						<u-icon name="edit-pen"></u-icon>
						<text>保存</text>
					</view>
				</view>
			</template>
		</u-navbar>
		<scroll-view @touchmove.stop :scroll-y="true" class="scroll_content" :rebound="false"
			:style="{height:scrollHeight+'px'}">
			<view class="form-box">
				<u-form :model="form" ref="uForm" :label-width="140">
					<u-form-item label="卡组名称" prop="name">
						<u-input v-model="form.name" />
					</u-form-item>
					<u-form-item label="关联商品" prop="goods_id" ref="goods_id">
						<view class="cell-item" @click="handelSetGoods">
							<text v-if="form.goods_id.length">已设置</text>
							<text v-else style="color: rgb(192, 196, 204);">未设置</text>
							<u-icon name="arrow-right" color="rgb(192, 196, 204)"></u-icon>
						</view>
					</u-form-item>
					<u-form-item label="页面模板" prop="template">
						<u-input :value="templateText" type="select" @click="showTemplate = true" />
						<u-action-sheet :list="templateList" v-model="showTemplate"
							@click="handelTemplateChange"></u-action-sheet>
					</u-form-item>
					<u-form-item label="卡组备注" prop="batch_mark">
						<u-input type="textarea" v-model="form.batch_mark" />
					</u-form-item>
					<u-form-item label="生成卡密" prop="need_create">
						<u-radio-group v-model="form.need_create">
							<u-radio :name="0">
								否
							</u-radio>
							<u-radio :name="1">
								是
							</u-radio>
						</u-radio-group>
					</u-form-item>
					<template v-if="form.need_create == 1">
						<u-form-item label="生成数量" prop="num">
							<u-number-box v-model="form.num"></u-number-box>
						</u-form-item>
						<u-form-item label="商品限价" prop="limit_price">
							<u-input v-model="form.limit_price" placeholder="商品限价默认0不限制，成本低于限价禁止兑换" />
						</u-form-item>
						<u-form-item label="过期时间" prop="expire_time">
							<uni-datetime-picker v-model="form.expire_time" type="datetime" />
						</u-form-item>
						<u-form-item label="生成备注" prop="mark">
							<u-input type="textarea" v-model="form.mark" />
						</u-form-item>
					</template>
				</u-form>
			</view>
		</scroll-view>
	</view>
</template>

<script>
	export default {
		data() {
			return {
				navbarTitle: '',
				scrollHeight: 0,

				showTemplate: false,
				templateList: [{
						text: '默认',
						value: 'default',
					},
					{
						text: '橙色',
						value: 'orange',
					},
				],

				batchId: '',
				form: {
					id: '',
					name: '',
					goods_id: [],
					template: 'default',
					is_kefu: 0,
					batch_mark: '',
					need_create: 0, // 是否创建卡密0不创建 1创建 下面参数=1时才显示
					num: 1,
					limit_price: '',
					expire_time: '',
					mark: ''
				},
				rules: {
					name: [{
						required: true,
						message: '请输入名称',
						trigger: ['change', 'blur']
					}],
					goods_id: [{
						type: 'array',
						required: true,
						message: '请选择商品',
						trigger: ['change', 'blur']
					}]
				},
			};
		},
		computed: {
			templateText() {
				if (this.form.template != '') {
					let find = this.templateList.find(item => item.value == this.form.template)
					return find.text
				} else {
					return ''
				}
			}
		},
		onLoad(e) {
			const {
				id
			} = e
			if (id) {
				this.navbarTitle = '编辑卡组'
				this.batchId = id
			} else
				this.navbarTitle = '添加卡组'
		},
		onShow() {
			if (this.batchId)
				this.getDetail(this.batchId)
		},
		onReady(e) {
			this.$refs.uForm.setRules(this.rules)

			this.$nextTick(() => {
				uni.createSelectorQuery().select(".scroll_content").boundingClientRect(res => {
					this.scrollHeight = this.deviceInfo.screenHeight - res.top
				}).exec()
			})
		},
		onHide() {
			// this.form = this.$options.data().form
		},
		methods: {
			// 卡组详情
			async getDetail(id) {
				const data = await this.$u.api.goodsCardBatchRead({
					id
				})
				this.form = Object.assign(this.form, {
					...data
				})
			},
			// 页面模板回调
			handelTemplateChange(e) {
				if (this.templateList[e].value)
					this.form.template = this.templateList[e].value
				else
					this.form.template = ''
			},
			// 关联商品点击
			handelSetGoods() {
				if (this.form.id)
					this.$util.on(`/pages/ucenter_sub/exchange/card_group_goods?id=${this.form.id}`)
				else
					this.$util.on(`/pages/ucenter_sub/exchange/card_group_goods_add`)
			},
			// 获取下一页面返回时 传递过来的参数
			setGoodsData({
				receivedParams
			}) {
				console.log(receivedParams)
				this.$refs.goods_id.resetField()
				let copy_ids = this.$u.deepClone(this.form.goods_id) || []
				receivedParams.map(item => {
					copy_ids.push(item.id)
				})
				let uniqueSet = new Set(copy_ids)
				this.form.goods_id = [...uniqueSet]
			},
			// 保存点击
			handelSaveClick() {
				this.$refs.uForm.validate(valid => {
					if (valid) {
						this.$u.throttle(async () => {
							await this.$u.api.goodsCardBatchSave(this.form)

							const pages = getCurrentPages()
							if (pages.length > 1) {
								uni.navigateBack({
									delta: 1, // 返回上一级页面
									success: function() {
										const prevPage = pages[pages.length - 2]; // 上一页面对象
										// 在上一页面中接收参数
										prevPage.reloadData()
									}
								})
							} else {
								this.$util.on('/pages/index/index')
							}
						}, 1000)
					} else {
						console.log('验证失败')
					}
				})
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	::v-deep {
		.u-form-item {
			font-size: 26rpx;
		}

		.u-input__input {
			font-size: 27rpx;
		}
	}

	.navbar-right {
		margin-right: 18rpx;
		display: flex;
		gap: 20rpx;

		.btn-item {}

		.btn-item:active {
			opacity: .6;
		}
	}

	.form-box {
		background-color: #fff;
		padding: 0 20rpx;

		.cell-item {
			display: flex;
			justify-content: space-between;
			width: 100%;
			cursor: pointer;
		}
	}

	.check-btn {
		padding: 4rpx 20rpx;
		background: linear-gradient(-90deg, #19be6b, #19be6b);
		border-radius: 44rpx;
		color: #fff;
	}

	::v-deep {
		.u-sticky-wrap {
			height: auto !important;
		}

		.uni-input-wrapper {
			font-size: 26rpx;
		}

		.uni-textarea-compute {
			font-size: 26rpx;
		}

		.u-form-item {
			font-size: 26rpx;
		}

		.uni-date-x {
			border-radius: 56rpx;

			.icon-calendar {
				padding-left: 24rpx;
			}
		}

		.uni-date-x--border {
			border-radius: 56rpx;
		}

		.uni-date__x-input {
			line-height: 60rpx;
			height: 60rpx;
		}

		.uni-input-input {
			font-size: 26rpx;
		}

		.u-size-default {
			font-size: 26rpx;
			height: 60rpx;
			line-height: 58rpx;
			padding: 0 80rpx;
			margin-top: 26rpx;
			background: linear-gradient(90deg, #FE8A56 0%, #FF504B 100%);
			border-radius: 60rpx;
			color: #fff;
		}

		.fail {
			background: linear-gradient(90deg, #353535 0%, #909399 100%);
		}

		.u-hairline-border::after {
			border-radius: 60rpx;
		}
	}
</style>